INSERT INTO books (title, author, publisher, year, pages, category, language, synopsis, moral) VALUES
  ('காணும் வாழ்க்கை','கவிஞர் வேலு','கலைஞன் பதிப்பகம்',1990,80,'நாவல்','Tamil','இந்நூல் வாழ்க்கை என்ற கருப்பொருளை மையமாக வைத்து மனித வாழ்க்கையின் ஆழமான உணர்வுகளை சித்தரிக்கிறது. வாசகர்களை ஒரு மறக்க முடியாத படிக்கும் பயணத்திற்கு அழைக்கிறது.','விடாமுயற்சியும் தன்னம்பிக்கையும் வாழ்க்கையில் வெற்றி பெறுவதற்கான அடிப்படை.'),
  ('காணும் காதல்','தமிழ்நாடன்','மணிவாசகர் பதிப்பகம்',1991,89,'சிறுகதை','Tamil','காதல் என்ற தலைப்பின் கீழ், ஆசிரியர் மனித உறவுகளின் நுட்பங்களையும் வாழ்க்கையின் பல்வேறு பரிமாணங்களையும் அழகுற சித்தரிக்கிறார்.','அன்பும் கருணையும் மனித சமுதாயத்தை இணைக்கும் பொன்னான கோடுகள்.'),
  ('காணும் நட்பு','மாலதி','தமிழ்நிலம் பதிப்பகம்',1992,98,'கவிதை','Tamil','இக்கதை நட்பு பற்றிய ஆழமான சிந்தனைகளை முன்வைக்கிறது. வீரம், விடாமுயற்சி மற்றும் அன்பின் மகத்துவத்தை உணர்த்தும் சிறந்த படைப்பு.','கல்வியும் அறிவும் ஒவ்வொரு மனிதனின் வாழ்க்கையை வளமாக்கும் அடித்தளம்.'),
  ('காணும் குடும்பம்','செல்வராஜ்','சாகித்திய அகாதெமி',1993,107,'வாழ்க்கை வரலாறு','Tamil','குடும்பம் ஐ பின்னணியாகக் கொண்டு, இந்நாவல் சமூகத்தின் பல்வேறு அடுக்குகளையும் மனித இயல்புகளையும் ஆழமாக ஆராய்கிறது.','நேர்மையும் ஒழுக்கமும் ஒரு நல்ல சமுதாயத்தை உருவாக்கும் முக்கியமான மதிப்புகள்.'),
  ('காணும் தாய்மை','கவிதா','பாரி நிலையம்',1994,116,'வரலாறு','Tamil','இந்த படைப்பு தாய்மை என்ற கருவை மையமாகக் கொண்டு, தமிழ் சமூகத்தின் பண்பாட்டு மரபுகளையும் நவீன வாழ்க்கையின் சவால்களையும் காட்டுகிறது.','குடும்பத்தின் அன்பும் நட்பின் மதிப்பும் வாழ்க்கையின் மிகப் பெரிய செல்வங்கள்.'),
  ('காணும் தந்தை','முருகேசன்','கலைஞன் பதிப்பகம்',1995,125,'தத்துவம்','Tamil','தந்தை பற்றிய இந்நூல், வாழ்க்கையின் அர்த்தம் தேடும் மனிதனின் உள் உலகை ஆராய்கிறது. உணர்ச்சிகரமான வர்ணனைகளுடன் கூடிய சிறந்த இலக்கியப் படைப்பு.','விடாமுயற்சியும் தன்னம்பிக்கையும் வாழ்க்கையில் வெற்றி பெறுவதற்கான அடிப்படை.'),
  ('காணும் மகன்','லட்சுமி','மணிவாசகர் பதிப்பகம்',1996,134,'அறிவியல்','Tamil','இந்நாவலில் மகன் என்ற கருப்பொருள் மனித வாழ்க்கையின் பல்வேறு நிலைகளை வெளிப்படுத்துகிறது. வாசகர்களை சிந்திக்கவும் உணரவும் வைக்கும் அழகான படைப்பு.','அன்பும் கருணையும் மனித சமுதாயத்தை இணைக்கும் பொன்னான கோடுகள்.'),
  ('காணும் மகள்','ராஜேந்திரன்','தமிழ்நிலம் பதிப்பகம்',1997,143,'உந்துதல்','Tamil','மகள் பற்றிய இந்த புத்தகம் தமிழ் இலக்கியத்தில் முக்கியமான இடத்தை பிடித்துள்ளது. உயரிய சிந்தனைகளும் நேர்த்தியான வர்ணனைகளும் இந்நூலை சிறப்பாக்குகின்றன.','கல்வியும் அறிவும் ஒவ்வொரு மனிதனின் வாழ்க்கையை வளமாக்கும் அடித்தளம்.'),
  ('காணும் உலகம்','சுகன்யா','சாகித்திய அகாதெமி',1998,152,'குழந்தை இலக்கியம்','Tamil','இந்நூல் உலகம் என்ற தலைப்பில் மனிதனின் அகத்துறை அனுபவங்களை ஆழமாக ஆராய்கிறது. வாசிக்க வாசிக்க ஆழமான உணர்வுகளை வழங்கும் படைப்பு.','நேர்மையும் ஒழுக்கமும் ஒரு நல்ல சமுதாயத்தை உருவாக்கும் முக்கியமான மதிப்புகள்.'),
  ('காணும் வானம்','பாரதிதாசன் குமார்','பாரி நிலையம்',1999,161,'இளைஞர் இலக்கியம்','Tamil','வானம் பற்றிய தத்துவ சிந்தனைகளையும் மனித வாழ்க்கையின் உண்மைகளையும் ஒருங்கிணைக்கும் இந்நூல் ஒவ்வொரு வாசகர் மனதிலும் நீண்டகாலம் நிலைத்திருக்கும்.','குடும்பத்தின் அன்பும் நட்பின் மதிப்பும் வாழ்க்கையின் மிகப் பெரிய செல்வங்கள்.'),
  ('காணும் கடல்','மீனாட்சி','கலைஞன் பதிப்பகம்',2000,170,'நாவல்','Tamil','இந்நூல் கடல் என்ற கருப்பொருளை மையமாக வைத்து மனித வாழ்க்கையின் ஆழமான உணர்வுகளை சித்தரிக்கிறது. வாசகர்களை ஒரு மறக்க முடியாத படிக்கும் பயணத்திற்கு அழைக்கிறது.','விடாமுயற்சியும் தன்னம்பிக்கையும் வாழ்க்கையில் வெற்றி பெறுவதற்கான அடிப்படை.'),
  ('காணும் மலை','அருண்குமார்','மணிவாசகர் பதிப்பகம்',2001,179,'சிறுகதை','Tamil','மலை என்ற தலைப்பின் கீழ், ஆசிரியர் மனித உறவுகளின் நுட்பங்களையும் வாழ்க்கையின் பல்வேறு பரிமாணங்களையும் அழகுற சித்தரிக்கிறார்.','அன்பும் கருணையும் மனித சமுதாயத்தை இணைக்கும் பொன்னான கோடுகள்.'),
  ('காணும் நதி','சரண்யா','தமிழ்நிலம் பதிப்பகம்',2002,188,'கவிதை','Tamil','இக்கதை நதி பற்றிய ஆழமான சிந்தனைகளை முன்வைக்கிறது. வீரம், விடாமுயற்சி மற்றும் அன்பின் மகத்துவத்தை உணர்த்தும் சிறந்த படைப்பு.','கல்வியும் அறிவும் ஒவ்வொரு மனிதனின் வாழ்க்கையை வளமாக்கும் அடித்தளம்.'),
  ('காணும் காடு','விஜயகுமார்','சாகித்திய அகாதெமி',2003,197,'வாழ்க்கை வரலாறு','Tamil','காடு ஐ பின்னணியாகக் கொண்டு, இந்நாவல் சமூகத்தின் பல்வேறு அடுக்குகளையும் மனித இயல்புகளையும் ஆழமாக ஆராய்கிறது.','நேர்மையும் ஒழுக்கமும் ஒரு நல்ல சமுதாயத்தை உருவாக்கும் முக்கியமான மதிப்புகள்.'),
  ('காணும் வீடு','நளினி','பாரி நிலையம்',2004,206,'வரலாறு','Tamil','இந்த படைப்பு வீடு என்ற கருவை மையமாகக் கொண்டு, தமிழ் சமூகத்தின் பண்பாட்டு மரபுகளையும் நவீன வாழ்க்கையின் சவால்களையும் காட்டுகிறது.','குடும்பத்தின் அன்பும் நட்பின் மதிப்பும் வாழ்க்கையின் மிகப் பெரிய செல்வங்கள்.'),
  ('காணும் ஊர்','சுந்தரம்','கலைஞன் பதிப்பகம்',2005,215,'தத்துவம்','Tamil','ஊர் பற்றிய இந்நூல், வாழ்க்கையின் அர்த்தம் தேடும் மனிதனின் உள் உலகை ஆராய்கிறது. உணர்ச்சிகரமான வர்ணனைகளுடன் கூடிய சிறந்த இலக்கியப் படைப்பு.','விடாமுயற்சியும் தன்னம்பிக்கையும் வாழ்க்கையில் வெற்றி பெறுவதற்கான அடிப்படை.'),
  ('காணும் நாடு','கலைவாணி','மணிவாசகர் பதிப்பகம்',2006,224,'அறிவியல்','Tamil','இந்நாவலில் நாடு என்ற கருப்பொருள் மனித வாழ்க்கையின் பல்வேறு நிலைகளை வெளிப்படுத்துகிறது. வாசகர்களை சிந்திக்கவும் உணரவும் வைக்கும் அழகான படைப்பு.','அன்பும் கருணையும் மனித சமுதாயத்தை இணைக்கும் பொன்னான கோடுகள்.'),
  ('காணும் இயற்கை','பழனிசாமி','தமிழ்நிலம் பதிப்பகம்',2007,233,'உந்துதல்','Tamil','இயற்கை பற்றிய இந்த புத்தகம் தமிழ் இலக்கியத்தில் முக்கியமான இடத்தை பிடித்துள்ளது. உயரிய சிந்தனைகளும் நேர்த்தியான வர்ணனைகளும் இந்நூலை சிறப்பாக்குகின்றன.','கல்வியும் அறிவும் ஒவ்வொரு மனிதனின் வாழ்க்கையை வளமாக்கும் அடித்தளம்.'),
  ('காணும் அறிவு','ஜெயலட்சுமி','சாகித்திய அகாதெமி',2008,242,'குழந்தை இலக்கியம்','Tamil','இந்நூல் அறிவு என்ற தலைப்பில் மனிதனின் அகத்துறை அனுபவங்களை ஆழமாக ஆராய்கிறது. வாசிக்க வாசிக்க ஆழமான உணர்வுகளை வழங்கும் படைப்பு.','நேர்மையும் ஒழுக்கமும் ஒரு நல்ல சமுதாயத்தை உருவாக்கும் முக்கியமான மதிப்புகள்.'),
  ('காணும் கல்வி','கோவிந்தசாமி','பாரி நிலையம்',2009,251,'இளைஞர் இலக்கியம்','Tamil','கல்வி பற்றிய தத்துவ சிந்தனைகளையும் மனித வாழ்க்கையின் உண்மைகளையும் ஒருங்கிணைக்கும் இந்நூல் ஒவ்வொரு வாசகர் மனதிலும் நீண்டகாலம் நிலைத்திருக்கும்.','குடும்பத்தின் அன்பும் நட்பின் மதிப்பும் வாழ்க்கையின் மிகப் பெரிய செல்வங்கள்.'),
  ('காணும் மொழி','கவிஞர் வேலு','கலைஞன் பதிப்பகம்',2010,260,'நாவல்','Tamil','இந்நூல் மொழி என்ற கருப்பொருளை மையமாக வைத்து மனித வாழ்க்கையின் ஆழமான உணர்வுகளை சித்தரிக்கிறது. வாசகர்களை ஒரு மறக்க முடியாத படிக்கும் பயணத்திற்கு அழைக்கிறது.','விடாமுயற்சியும் தன்னம்பிக்கையும் வாழ்க்கையில் வெற்றி பெறுவதற்கான அடிப்படை.'),
  ('காணும் பண்பாடு','தமிழ்நாடன்','மணிவாசகர் பதிப்பகம்',2011,269,'சிறுகதை','Tamil','பண்பாடு என்ற தலைப்பின் கீழ், ஆசிரியர் மனித உறவுகளின் நுட்பங்களையும் வாழ்க்கையின் பல்வேறு பரிமாணங்களையும் அழகுற சித்தரிக்கிறார்.','அன்பும் கருணையும் மனித சமுதாயத்தை இணைக்கும் பொன்னான கோடுகள்.'),
  ('காணும் வரலாறு','மாலதி','தமிழ்நிலம் பதிப்பகம்',2012,278,'கவிதை','Tamil','இக்கதை வரலாறு பற்றிய ஆழமான சிந்தனைகளை முன்வைக்கிறது. வீரம், விடாமுயற்சி மற்றும் அன்பின் மகத்துவத்தை உணர்த்தும் சிறந்த படைப்பு.','கல்வியும் அறிவும் ஒவ்வொரு மனிதனின் வாழ்க்கையை வளமாக்கும் அடித்தளம்.'),
  ('காணும் கலை','செல்வராஜ்','சாகித்திய அகாதெமி',2013,287,'வாழ்க்கை வரலாறு','Tamil','கலை ஐ பின்னணியாகக் கொண்டு, இந்நாவல் சமூகத்தின் பல்வேறு அடுக்குகளையும் மனித இயல்புகளையும் ஆழமாக ஆராய்கிறது.','நேர்மையும் ஒழுக்கமும் ஒரு நல்ல சமுதாயத்தை உருவாக்கும் முக்கியமான மதிப்புகள்.'),
  ('காணும் இசை','கவிதா','பாரி நிலையம்',2014,296,'வரலாறு','Tamil','இந்த படைப்பு இசை என்ற கருவை மையமாகக் கொண்டு, தமிழ் சமூகத்தின் பண்பாட்டு மரபுகளையும் நவீன வாழ்க்கையின் சவால்களையும் காட்டுகிறது.','குடும்பத்தின் அன்பும் நட்பின் மதிப்பும் வாழ்க்கையின் மிகப் பெரிய செல்வங்கள்.'),
  ('காணும் கவிதை','முருகேசன்','கலைஞன் பதிப்பகம்',2015,305,'தத்துவம்','Tamil','கவிதை பற்றிய இந்நூல், வாழ்க்கையின் அர்த்தம் தேடும் மனிதனின் உள் உலகை ஆராய்கிறது. உணர்ச்சிகரமான வர்ணனைகளுடன் கூடிய சிறந்த இலக்கியப் படைப்பு.','விடாமுயற்சியும் தன்னம்பிக்கையும் வாழ்க்கையில் வெற்றி பெறுவதற்கான அடிப்படை.'),
  ('காணும் கதை','லட்சுமி','மணிவாசகர் பதிப்பகம்',2016,314,'அறிவியல்','Tamil','இந்நாவலில் கதை என்ற கருப்பொருள் மனித வாழ்க்கையின் பல்வேறு நிலைகளை வெளிப்படுத்துகிறது. வாசகர்களை சிந்திக்கவும் உணரவும் வைக்கும் அழகான படைப்பு.','அன்பும் கருணையும் மனித சமுதாயத்தை இணைக்கும் பொன்னான கோடுகள்.'),
  ('காணும் புரட்சி','ராஜேந்திரன்','தமிழ்நிலம் பதிப்பகம்',2017,323,'உந்துதல்','Tamil','புரட்சி பற்றிய இந்த புத்தகம் தமிழ் இலக்கியத்தில் முக்கியமான இடத்தை பிடித்துள்ளது. உயரிய சிந்தனைகளும் நேர்த்தியான வர்ணனைகளும் இந்நூலை சிறப்பாக்குகின்றன.','கல்வியும் அறிவும் ஒவ்வொரு மனிதனின் வாழ்க்கையை வளமாக்கும் அடித்தளம்.'),
  ('காணும் சுதந்திரம்','சுகன்யா','சாகித்திய அகாதெமி',2018,332,'குழந்தை இலக்கியம்','Tamil','இந்நூல் சுதந்திரம் என்ற தலைப்பில் மனிதனின் அகத்துறை அனுபவங்களை ஆழமாக ஆராய்கிறது. வாசிக்க வாசிக்க ஆழமான உணர்வுகளை வழங்கும் படைப்பு.','நேர்மையும் ஒழுக்கமும் ஒரு நல்ல சமுதாயத்தை உருவாக்கும் முக்கியமான மதிப்புகள்.'),
  ('காணும் அமைதி','பாரதிதாசன் குமார்','பாரி நிலையம்',2019,341,'இளைஞர் இலக்கியம்','Tamil','அமைதி பற்றிய தத்துவ சிந்தனைகளையும் மனித வாழ்க்கையின் உண்மைகளையும் ஒருங்கிணைக்கும் இந்நூல் ஒவ்வொரு வாசகர் மனதிலும் நீண்டகாலம் நிலைத்திருக்கும்.','குடும்பத்தின் அன்பும் நட்பின் மதிப்பும் வாழ்க்கையின் மிகப் பெரிய செல்வங்கள்.'),
  ('காணும் அன்பு','மீனாட்சி','கலைஞன் பதிப்பகம்',2020,350,'நாவல்','Tamil','இந்நூல் அன்பு என்ற கருப்பொருளை மையமாக வைத்து மனித வாழ்க்கையின் ஆழமான உணர்வுகளை சித்தரிக்கிறது. வாசகர்களை ஒரு மறக்க முடியாத படிக்கும் பயணத்திற்கு அழைக்கிறது.','விடாமுயற்சியும் தன்னம்பிக்கையும் வாழ்க்கையில் வெற்றி பெறுவதற்கான அடிப்படை.'),
  ('காணும் கருணை','அருண்குமார்','மணிவாசகர் பதிப்பகம்',2021,359,'சிறுகதை','Tamil','கருணை என்ற தலைப்பின் கீழ், ஆசிரியர் மனித உறவுகளின் நுட்பங்களையும் வாழ்க்கையின் பல்வேறு பரிமாணங்களையும் அழகுற சித்தரிக்கிறார்.','அன்பும் கருணையும் மனித சமுதாயத்தை இணைக்கும் பொன்னான கோடுகள்.'),
  ('காணும் தர்மம்','சரண்யா','தமிழ்நிலம் பதிப்பகம்',2022,368,'கவிதை','Tamil','இக்கதை தர்மம் பற்றிய ஆழமான சிந்தனைகளை முன்வைக்கிறது. வீரம், விடாமுயற்சி மற்றும் அன்பின் மகத்துவத்தை உணர்த்தும் சிறந்த படைப்பு.','கல்வியும் அறிவும் ஒவ்வொரு மனிதனின் வாழ்க்கையை வளமாக்கும் அடித்தளம்.'),
